Messages(prev => [...prev, userMessage]);\n    setInput('');\n    setIsThinking(true);\n    \n    try {\n      const response = await getAIResponse([...messages, userMessage]);\n      setMessages(prev => [...prev, response]);\n    } catch (error) {\n      console.error('AI Error:', error);\n    } finally {\n      setIsThinking(false);\n    }\n  };\n\n  return (\n    <div className=\"flex-1 flex flex-col bg-transparent relative overflow-hidden\">\n      {/* Decorative background gradients for the chat container */}\n      <div className=\"absolute top-0 left-0 w-full h-[300px] bg-gradient-to-b from-[#0b0e14] to-transparent z-0 pointer-events-none\"></div>\n      <div className=\"absolute bottom-0 left-0 w-full h-[400px] bg-gradient-to-t from-[#0b0e14]/90 via-[#0b0e14]/50 to-transparent z-0 pointer-events-none\"></div>\n\n      {/* Messages Area */}\n      <div \n        ref={scrollRef}\n        className=\"flex-1 overflow-y-auto px-6 py-12 md:px-12 xl:px-24 space-y-10 scrollbar-hide z-10\"\n      >\n        {messages.length === 0 && (\n          <div className=\"h-full flex flex-col items-center justify-center opacity-30 text-center\">\n            <Cpu className=\"w-16 h-16 text-primary mb-4\" />\n            <h2 className=\"font-headline text-2xl text-white font-bold\">Obsidian Terminal Ready</h2>\n            <p className=\"text-sm text-tertiary\">Awaiting your tactical instructions.</p>\n          </div>\n        )}\n        \n        <div className=\"max-w-4xl mx-auto w-full space-y-10 pb-20\">\n          {messages.map((msg) => (\n            <ChatMessage key={msg.id} message={msg} />\n          ))}\n          {isThinking && (\n            <div className=\"flex flex-col gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500\">\n              <div className=\"flex items-center gap-3\">\n                <div className=\"flex items-center gap-2 bg-secondary-container/10 border border-secondary-container/30 px-4 py-2 rounded-full backdrop-blur-md\">\n                  <Loader2 className=\"w-3.5 h-3.5 text-secondary-container animate-spin\" />\n                  <span className=\"text-[10px] font-bold text-secondary-container uppercase tracking-widest\">Synthesizing Alpha Data...</span>\n                </div>\n                <div className=\"flex items-center gap-2 bg-primary/10 border border-primary/20 px-4 py-2 rounded-full opacity-50 backdrop-blur-md\">\n                  <Globe className=\"w-3.5 h-3.5 text-primary\" />\n                  <span className=\"text-[10px] font-bold text-primary uppercase tracking-widest\">Querying ET Markets</span>\n                </div>\n              </div>\n            </div>\n          )}\n        </div>\n      </div>\n\n      {/* Floating Input Area */}\n      <div className=\"p-6 md:p-8 pt-0 z-20 pb-10\">\n        <div className=\"max-w-4xl mx-auto relative group\">\n          <div className=\"absolute -inset-1 bg-gradient-to-r from-primary/10 via-secondary-container/10 to-primary/10 rounded-3xl blur-md opacity-0 group-focus-within:opacity-100 transition-opacity duration-700\"></div>\n          \n          <div className=\"relative bg-[#0d1118]/80 hover:bg-[#12161f]/90 transition-colors border border-white/10 group-focus-within:border-primary/30 rounded-2xl p-2.5 flex items-center gap-3 shadow-2xl backdrop-blur-xl\">\n            <div className=\"p-3 text-white/30 group-focus-within:text-primary transition-colors\">\n              <Cpu className=\"w-5 h-5\" />\n            </div>\n            <input \n              type=\"text\" \n              value={input}\n              onChange={(e) => setInput(e.target.value)}\n              onKeyDown={(e) => e.key === 'Enter' && handleSend()}\n              placeholder=\"Enter instructions or query Obsidian Flux...\" \n              className=\"flex-1 bg-transparent border-none focus:ring-0 text-white placeholder:text-white/30 font-medium text-[15px] py-3 outline-none\"\n            />\n            <button \n              onClick={handleSend}\n              disabled={!input.trim() || isThinking}\n              className=\"bg-white/5 hover:bg-primary hover:text-black group-focus-within:bg-primary group-focus-within:text-black text-white px-6 py-3.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all active:scale-95 flex items-center gap-2.5 disabled:opacity-30 disabled:pointer-events-none\"\n            >\n              Execute <Send className=\"w-4 h-4\" />\n            </button>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n};\n"},{"path":"components/chat/ChatMessage.tsx","size":1103,"sha256":"24d0379a925cd7acff26245cff38663025eea28ee1ea22da98d4fb82ae6e8cba","encoding":"utf8","content":"import { motion } from 'motion/react';\nimport { Message } from '../../types';\n\ninterface ChatMessageProps {\n  message: Message;\n}\n\nexport const ChatMessage = ({ message }: ChatMessageProps) => {\n  const isAssistant = message.role === 'assistant';\n  \n  return (\n    <motion.div\n      initial={{ opacity: 0, y: 10 }}\n      animate={{ opacity: 1, y: 0 }}\n      className={`flex flex-col gap-3 ${isAssistant ? '' : 'items-end'}`}\n    >\n      <div className=\"flex items-center gap-2 text-[10px] text-tertiary uppercase tracking-widest font-bold\">\n        {isAssistant && (\n          <span className=\"w-2 h-2 rounded-full bg-secondary-container shadow-[0_0_8px_#00f1fe]\"></span>\n        )}\n        {isAssistant ? 'Flux System Core' : 'Institutional Client'}\n      </div>\n      \n      <div className={`rounded-2xl p-6 text-sm md:text-base leading-relaxed border border-white/5 shadow-xl max-w-[85%] ${\n        isAssistant \n          ? 'bg-surface-container-high text-white' \n          : 'bg-primary/10 text-primary border-primary/30'\n      }`}>\n        {message.content}\n      </div>\n    </motion.div>\n  );\n};\n"},{"path":"components/chat/ThinkingIndicator.tsx","size":796,"sha256":"f120f87140ba9678ffeace611f630547b56ba3517da1d3910bad0b92dd200b8f","encoding":"utf8","content":"import { motion } from 'motion/react';\n\nexport const ThinkingIndicator = () => {\n  return (\n    <div className=\"flex items-center gap-3 p-6 bg-white/[0.02] border-y border-white/5\">\n      <div className=\"flex gap-1\">\n        {[0, 1, 2].map((i) => (\n          <motion.div\n            key={i}\n            animate={{\n              scale: [1, 1.5, 1],\n              opacity: [0.3, 1, 0.3],\n            }}\n            transition={{\n              duration: 1,\n              repeat: Infinity,\n              delay: i * 0.2,\n            }}\n            className=\"w-1.5 h-1.5 bg-orange-500 rounded-full\"\n          />\n        ))}\n      </div>\n      <span className=\"text-[10px] font-bold uppercase tracking-[0.2em] text-orange-500/60\">\n        AI is processing flux data...\n      </span>\n    </div>\n  );\n};\n"},{"path":"components/layout/Navbar.tsx","size":2872,"sha256":"b65e734a012a039572cd9326b4dfa5f959121ed47cf584b6ae90942fa502c962","encoding":"utf8","content":"'use client';\n\nimport Link from 'next/link';\nimport { usePathname } from 'next/navigation';\nimport { Shield, Terminal, PieChart, Library, BarChart3, Bell, Settings, Search, Wallet } from 'lucide-react';\nimport Image from 'next/image';\n\nexport const Navbar = () => {\n  const pathname = usePathname();\n\n  return (\n    <header className=\"fixed top-0 w-full z-50 bg-background/80 backdrop-blur-xl border-b border-white/5\">\n      <nav className=\"flex justify-between items-center px-6 h-16 w-full max-w-[1920px] mx-auto relative\">\n        <div className=\"flex flex-1 items-center gap-10\">\n          <Link href=\"/\" className=\"flex items-center gap-2 group\">\n            <span className=\"text-xl font-bold tracking-tighter text-white\">Obsidian Flux</span>\n            \n          </Link>\n        </div>\n          \n        <div className=\"hidden md:flex items-center justify-center gap-8 absolute left-1/2 -translate-x-1/2 w-max\">\n          <Link href=\"/chat\" className={`transition-colors flex items-center gap-2 text-sm ${pathname === '/chat' ? 'text-primary font-bold drop-shadow-[0_0_8px_rgba(var(--primary),0.8)]' : 'text-tertiary hover:text-white'}`}>\n            <Terminal className=\"w-4 h-4\" /> The Terminal\n          </Link>\n          <Link href=\"/simulation\" className={`transition-colors flex items-center gap-2 text-sm ${pathname === '/simulation' ? 'text-primary font-bold drop-shadow-[0_0_8px_rgba(var(--primary),0.8)]' : 'text-tertiary hover:text-white'}`}>\n            <BarChart3 className=\"w-4 h-4\" /> Future Simulation\n          </Link>\n          <Link href=\"/hub\" className={`transition-colors flex items-center gap-2 text-sm ${pathname === '/hub' ? 'text-primary font-bold drop-shadow-[0_0_8px_rgba(var(--primary),0.8)]' : 'text-tertiary hover:text-white'}`}>\n            <Library className=\"w-4 h-4\" /> Active Hub\n          </Link>\n        </div>\n        \n        <div className=\"flex flex-1 justify-end items-center gap-4\">\n          \n          <div className=\"h-6 w-px bg-white/10 mx-2\"></div>\n          <button className=\"p-2 text-tertiary hover:text-white rounded-full transition-colors relative\">\n            <Bell className=\"w-5 h-5\" />\n            <span className=\"absolute top-2 right-2 w-2 h-2 bg-primary rounded-full border-2 border-background\"></span>\n          </button>\n          <button className=\"p-2 text-tertiary hover:text-white rounded-full transition-colors\">\n            <Settings className=\"w-5 h-5\" />\n          </button>\n          <div className=\"w-8 h-8 rounded-full overflow-hidden border border-white/10 ml-2 ring-2 ring-primary/20 relative\">\n            <Image \n              alt=\"User\" \n              src=\"https://picsum.photos/seed/user/100/100\" \n              fill\n              className=\"object-cover\"\n              referrerPolicy=\"no-referrer\"\n            />\n          </div>\n        </div>\n      </nav>\n    </header>\n  );\n};\n"},{"path":"components/profile/ProfilePanel.tsx","size":4715,"sha256":"a2b8929545018b8d48b6d6b82b17a7ff9b07f502d94ce6f37468bdbbb20d621b","encoding":"utf8","content":"import { UserProfile } from '../../types';\nimport { Bolt, ShieldCheck } from 'lucide-react';\n\ninterface ProfilePanelProps {\n  profile: UserProfile;\n}\n\nexport const ProfilePanel = ({ profile }: ProfilePanelProps) => {\n  return (\n    <section className=\"flex flex-col space-y-8 pt-4 border-t border-white/5 mt-6\">\n      <div className=\"space-y-6\">\n        <div className=\"flex items-center justify-between\">\n          <div>\n            <h2 className=\"font-headline text-xl font-extrabold tracking-tight\">Intelligence</h2>\n            <p className=\"text-tertiary text-[10px] uppercase font-bold tracking-widest\">Heuristic Vector Mapping</p>\n          </div>\n          <div className=\"w-10 h-10 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center\">\n            <Bolt className=\"w-5 h-5 text-primary\" />\n          </div>\n        </div>\n\n        {/* Central Radial Dial */}\n        <div className=\"bg-surface-container-low rounded-2xl p-6 flex flex-col items-center justify-center relative overflow-hidden border border-white/5\">\n          <div className=\"relative w-40 h-40 flex items-center justify-center\">\n            <svg className=\"w-full h-full transform -rotate-90\">\n              <circle \n                className=\"text-white/5\" \n                cx=\"80\" cy=\"80\" fill=\"transparent\" r=\"70\" \n                stroke=\"currentColor\" strokeWidth=\"6\"\n              />\n              <circle \n                className=\"text-primary drop-shadow-[0_0_8px_rgba(0,200,5,0.5)]\" \n                cx=\"80\" cy=\"80\" fill=\"transparent\" r=\"70\" \n                stroke=\"currentColor\" strokeWidth=\"6\"\n                strokeDasharray=\"440\"\n                strokeDashoffset=\"66\"\n              />\n            </svg>\n            <div className=\"absolute inset-0 flex flex-col items-center justify-center text-center\">\n              <span className=\"text-6xl font-black font-headline text-white\">85</span>\n              <span className=\"text-tertiary text-[8px] font-bold uppercase tracking-widest\">Financial IQ</span>\n            </div>\n          </div>\n        </div>\n\n        {/* Fluid Progress Bars */}\n        <div className=\"space-y-6\">\n          <div className=\"space-y-3\">\n            <div className=\"flex justify-between items-end\">\n              <label className=\"text-[10px] font-bold text-tertiary uppercase tracking-widest\">Risk Appetite</label>\n              <span className=\"text-primary text-xs font-bold\">Aggressive</span>\n            </div>\n            <div className=\"h-1.5 w-full bg-white/5 rounded-full overflow-hidden\">\n              <div className=\"h-full w-[78%] bg-gradient-to-r from-primary/50 to-primary rounded-full neon-glow\"></div>\n            </div>\n          </div>\n          <div className=\"space-y-3\">\n            <div className=\"flex justify-between items-end\">\n              <label className=\"text-[10px] font-bold text-tertiary uppercase tracking-widest\">Experience</label>\n              <span className=\"text-secondary-container text-xs font-bold\">Institutional</span>\n            </div>\n            <div className=\"h-1.5 w-full bg-white/5 rounded-full overflow-hidden\">\n              <div className=\"h-full w-[92%] bg-gradient-to-r from-secondary-container/50 to-secondary-container rounded-full\"></div>\n            </div>\n          </div>\n        </div>\n\n        {/* Goals Distribution */}\n        <div className=\"pt-4\">\n          <h4 className=\"text-[10px] font-bold text-tertiary uppercase tracking-widest mb-6\">Distribution Map</h4>\n          <div className=\"flex items-center justify-center relative h-32\">\n            <div className=\"relative w-24 h-24\">\n              <div className=\"absolute inset-0 border border-white/10 rounded-full rotate-45\"></div>\n              <div className=\"absolute inset-4 border border-white/10 rounded-full rotate-45\"></div>\n              <svg className=\"absolute inset-0 w-full h-full text-secondary-container/30 fill-secondary-container/10\">\n                <polygon points=\"48,10 85,30 75,80 20,70 10,40\" stroke=\"currentColor\" strokeWidth=\"1.5\"></polygon>\n              </svg>\n            </div>\n            <div className=\"absolute top-0 text-[8px] font-bold text-tertiary\">GROWTH</div>\n            <div className=\"absolute bottom-0 text-[8px] font-bold text-tertiary\">HEDGE</div>\n          </div>\n        </div>\n      </div>\n\n      {/* Verification Footer */}\n      <div className=\"mt-auto pt-6 border-t border-white/5 text-center\">\n        <div className=\"flex items-center justify-center gap-2\">\n          <ShieldCheck className=\"w-4 h-4 text-primary\" />\n          <span className=\"text-[10px] text-tertiary uppercase font-bold tracking-widest\">Core ID: OX-992-FLUX</span>\n        </div>\n      </div>\n    </section>\n  );\n};\n"},{"path":"components/recommendation/RecommendationCard.tsx","size":1910,"sha256":"5a905999e63d9782f35e79efc53a9858a3bcac36aea119a387ca78c0950f86e3","encoding":"utf8","content":"import { Recommendation } from '../../types';\nimport { motion } from 'motion/react';\n\ninterface RecommendationCardProps {\n  recommendation: Recommendation;\n}\n\nexport const RecommendationCard = ({ recommendation }: RecommendationCardProps) => {\n  const isHighMatch = recommendation.confidence >= 0.9;\n  \n  return (\n    <motion.div\n      whileHover={{ y: -2 }}\n      className={`bg-surface-container-high rounded-2xl p-5 border border-white/5 hover:border-primary/30 transition-all group cursor-pointer ${recommendation.confidence < 0.7 ? 'opacity-50 grayscale hover:grayscale-0 hover:opacity-100' : ''}`}\n    >\n      <div className=\"flex justify-between items-start mb-4\">\n        <div>\n          <h4 className=\"font-bold text-white group-hover:text-primary transition-colors\">{recommendation.title}</h4>\n          <p className=\"text-[10px] text-tertiary uppercase tracking-tighter\">Global Alpha Cluster</p>\n        </div>\n        <div className=\"text-right\">\n          <div className={`text-2xl font-black font-headline ${isHighMatch ? 'text-primary' : 'text-secondary-container'}`}>\n            {(recommendation.confidence * 100).toFixed(0)}%\n          </div>\n          <div className=\"text-[8px] text-tertiary uppercase font-bold\">Match</div>\n        </div>\n      </div>\n      \n      <div className={`bg-black/40 rounded-lg p-3 mb-4 border-l-2 ${isHighMatch ? 'border-primary' : 'border-secondary-container'}`}>\n        <p className=\"text-xs text-tertiary leading-relaxed italic\">\n          &quot;{recommendation.reasoning}&quot;\n        </p>\n      </div>\n      \n      <button className={`w-full py-2.5 text-xs font-bold rounded-lg transition-all ${isHighMatch ? 'bg-primary text-black hover:brightness-110' : 'border border-secondary-container text-secondary-container hover:bg-secondary-container/10'}`}>\n        {isHighMatch ? 'Deploy Sequence' : 'View Details'}\n      </button>\n    </motion.div>\n  );\n};\n"},{"path":"components/ui/AIOrb.tsx","size":1457,"sha256":"df77fdc39d14655f23aed3bef063a607cf3cc7ff594ab107e096284a1bfd7bac","encoding":"utf8","content":"import { motion } from 'motion/react';\n\nexport const AIOrb = () => {\n  return (\n    <div className=\"relative w-[400px] h-[400px] flex items-center justify-center\">\n      {/* Outer Glow */}\n      <motion.div\n        animate={{\n          scale: [1, 1.2, 1],\n          opacity: [0.3, 0.6, 0.3],\n        }}\n        transition={{\n          duration: 4,\n          repeat: Infinity,\n          ease: \"easeInOut\",\n        }}\n        className=\"absolute inset-0 bg-primary/20 blur-[100px] rounded-full\"\n      />\n      \n      {/* Core */}\n      <motion.div\n        animate={{\n          scale: [1, 1.2, 1],\n          opacity: [0.6, 0.9, 0.6],\n        }}\n        transition={{\n          duration: 10,\n          repeat: Infinity,\n          ease: \"easeInOut\",\n        }}\n        className=\"relative w-[240px] h-[240px] rounded-full bg-radial-[circle_at_30%_30%] from-primary to-[#004d02] shadow-[0_0_60px_rgba(0,200,5,0.6),inset_-10px_-10px_40px_rgba(0,0,0,0.5)] z-2\"\n      />\n      \n      {/* Orbiting Rings */}\n      <motion.div \n        animate={{ rotate: 360 }}\n        transition={{ duration: 8, repeat: Infinity, ease: \"linear\" }}\n        className=\"absolute inset-0 border-2 border-primary/20 rounded-full\" \n      />\n      <motion.div \n        animate={{ rotate: -360 }}\n        transition={{ duration: 15, repeat: Infinity, ease: \"linear\" }}\n        className=\"absolute inset-[10%] border border-dashed border-primary/40 rounded-full\" \n      />\n    </div>\n  );\n};\n"},{"path":"lib/api.ts","size":1142,"sha256":"cf7cb296ffb9aa0c151b7f230eebe848aa8ac5ac89c86a9332cc4a03088995e3","encoding":"utf8","content":"import { Message, Recommendation, UserProfile } from '../types';\nimport { DUMMY_MESSAGES, DUMMY_RECOMMENDATIONS, DUMMY_PROFILE } from './dummyData';\n\nexport async function analyzeUserMessage(message: string): Promise<string> {\n  // Simulate AI thinking delay\n  await new Promise(resolve => setTimeout(resolve, 1500));\n  return `I have analyzed your request: \"${message}\". Based on the current ET market flux, I recommend exploring our high-yield obsidian pools.`;\n}\n\nexport async function getAIResponse(messages: Message[]): Promise<Message> {\n  const lastMessage = messages[messages.length - 1];\n  const responseContent = await analyzeUserMessage(lastMessage.content);\n  \n  return {\n    id: Math.random().toString(36).substring(7),\n    role: 'assistant',\n    content: responseContent,\n    timestamp: new Date(),\n    status: 'complete'\n  };\n}\n\nexport async function getRecommendations(profile: UserProfile): Promise<Recommendation[]> {\n  // Simulate API call\n  await new Promise(resolve => setTimeout(resolve, 1000));\n  return DUMMY_RECOMMENDATIONS;\n}\n\nexport async function getUserProfile(): Promise<UserProfile> {\n  return DUMMY_PROFILE;\n}\n"},{"path":"lib/dummyData.ts","size":1121,"sha256":"91dc13a33cc74fe2ee1ff040053a18ba6e029b55cd0771aa1dfa53b08a0a7d58","encoding":"utf8","content":"import { Message, Recommendation, UserProfile } from '../types';\n\nexport const DUMMY_MESSAGES: Message[] = [\n  {\n    id: '1',\n    role: 'assistant',\n    content: 'Welcome to Obsidian Flux. I am your ET AI Concierge. How can I assist your financial journey today?',\n    timestamp: new Date(),\n    status: 'complete'\n  }\n];\n\nexport const DUMMY_RECOMMENDATIONS: Recommendation[] = [\n  {\n    id: 'rec-1',\n    title: 'ET Alpha Growth Fund',\n    description: 'High-performance tech-focused equity fund.',\n    confidence: 0.94,\n    reasoning: 'Matches your medium-high risk tolerance and interest in emerging technologies.',\n    actions: ['View Prospectus', 'Simulate Returns']\n  },\n  {\n    id: 'rec-2',\n    title: 'Obsidian Yield Optimizer',\n    description: 'AI-managed stablecoin yield farming.',\n    confidence: 0.88,\n    reasoning: 'Optimizes passive income while maintaining liquidity.',\n    actions: ['Connect Wallet', 'View Strategy']\n  }\n];\n\nexport const DUMMY_PROFILE: UserProfile = {\n  name: 'Elite User',\n  riskTolerance: 'medium',\n  interests: ['DeFi', 'AI Tech', 'Sustainable Energy'],\n  lastActive: new Date()\n};\n"},{"path":"lib/server/personalization.ts","size":8370,"sha256":"d85aceeb8c0983065685afaa5af734769115fcb85760aed1b5a0f147cdb94d50","encoding":"utf8","content":"import { GoogleGenerativeAI } from '@google/generative-ai';\nimport {\n  DEFAULT_HUB_ITEMS,\n  DEFAULT_RECOMMENDATIONS,\n  DEFAULT_SIMULATION,\n  DEFAULT_PROFILE,\n  PROFILING_QUESTIONS,\n} from '../dummyData';\nimport { Message, PersonalizationPayload, UserProfile } from '../../types';\n\nexport async function personalizeSession(session: PersonalizationPayload, userInput: string): Promise<PersonalizationPayload> {\n  const userMessage: Message = {\n    id: crypto.randomUUID(),\n    role: 'user',\n    content: userInput,\n    timestamp: new Date().toISOString(),\n    status: 'complete',\n  };\n\n  const messages = [...session.messages, userMessage];\n  let isJustFinished = false;\n\n  const apiKey = process.env.GEMINI_API_KEY?.replace(/\"/g, '');\n  if (!apiKey) {\n    throw new Error(\"Missing GEMINI_API_KEY\");\n  }\n\n  const genAI = new GoogleGenerativeAI(apiKey);\n  const model = genAI.getGenerativeModel({\n    model: 'gemini-2.5-flash',\n    generationConfig: { responseMimeType: 'application/json' }\n  });\n\n  const conversationString = messages.map(m => `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.content}`).join('\\n');\n\n  let assistantReply = \"\";\n  let updatedSession = { ...session, messages };\n\n  if (!session.profilingComplete) {\n    const profilingPrompt = `\nYou are the ET AI Concierge for The Economic Times ecosystem.\nYour goal is to guide the user through a short onboarding process consisting of exactly 10 questions.\nWe need to figure out their financial profile.\n\nHere is the list of target questions to ask recursively:\n${PROFILING_QUESTIONS.map((q, i) => `${i + 1}. ${q.prompt}`).join('\\n')}\n\nThe user has answered ${session.answeredQuestions} questions so far.\n\nConversation History:\n${conversationString.replace(/`/g, \"'\")}\n\nINSTRUCTIONS:\n1. Look at the user's latest response.\n2. If they make small talk or ask a side question, answer it briefly, AND THEN ask the NEXT pending question from the list.\n3. If they answered the question adequately, increment the answered question count in your head and ask the NEXT question on the list.\n4. Keep your responses short, professional, conversational, and direct.\n\nOUTPUT (JSON MATCHING SCHEMA):\n{\n  \"assistantReply\": \"Your response to them and the next question text.\",\n  \"newAnsweredCount\": <number>, \n  \"isProfilingComplete\": <boolean>\n}\n**Ensure isProfilingComplete is true ONLY if newAnsweredCount is 10 or more**\n`;\n\n    try {\n      const result = await model.generateContent(profilingPrompt);\n      const data = JSON.parse(result.response.text());\n      \n      assistantReply = data.assistantReply;\n      updatedSession.answeredQuestions = data.newAnsweredCount;\n      \n      if (data.isProfilingComplete) {\n        updatedSession.profilingComplete = true;\n        isJustFinished = true; // Trigger the dashboard generation in stage 2\n      }\n    } catch (err: any) {\n      console.error(\"Gemini Profiling Error:\", err.message);\n      assistantReply = \"I'm having a slight connection hiccup right now. Could you repeat that?\";\n    }\n\n  } else {\n    // Stage 3: General Chat Post-Profiling\n    // In this branch, Gemini answers general queries contextually as the ET AI Concierge\n    const chatModel = genAI.getGenerativeModel({ model: 'gemini-2.5-flash' });\n    const postProfilingPrompt = `\nYou are the ET AI Concierge for The Economic Times ecosystem. The user has already finished their onboarding.\nTheir profile summary: ${updatedSession.profile?.summary || 'User is looking for ET insights.'}\nTheir main goal: ${updatedSession.profile?.primaryGoal || 'Financial growth'}\nRisk Level: ${updatedSession.profile?.riskLabel || 'Balanced'}\n\nConversation History:\n${conversationString.replace(/`/g, \"'\")}\n\nRespond strictly in plain text / conversational format to their latest message. You can recommend ET topics, talk about macro, or adjust their profile via conversation. Keep your responses crisp, direct, and under 4-5 sentences.\n`;\n    try {\n      const result = await chatModel.generateContent(postProfilingPrompt);\n      assistantReply = result.response.text().trim();\n    } catch (err: any) {\n      console.error(\"Gemini Chat Error:\", err.message);\n      if (err.message.includes(\"429 Too Many Requests\") || err.message.includes(\"Quota\")) {\n        assistantReply = \"I'm hitting a quick rate limit with Gemini right now because of the free tier. Please wait about 60 seconds and try again!\";\n      } else {\n        assistantReply = \"I'm experiencing a quick interruption; could you rephrase that?\";\n      }\n    }\n  }\n\n  // Generate Profile & Recommendations Dashboard\n  // This triggers right after they answer the 10th question OR if it was already complete but we haven't generated the real recommendations yet\n  if (isJustFinished || (session.profilingComplete && session.recommendations.length > 0 && session.recommendations[0].id === 'rec-prime')) {\n    console.log(\"Profiling complete! Generating recommendations dashboard...\");\n    \n    const synthesisPrompt = `\nYou are the ET AI Concierge expert data generator.\nThe user has just finished answering their 10 onboarding financial questions.\n\nConversation History:\n${conversationString.replace(/`/g, \"'\")}\n\nBased ON THEIR ANSWERS, generate a fully personalized user profile, and exactly 3 hyper-targeted \"recommendations\" for ET (Economic Times) products/features.\n\nCRITICAL LINK INSTRUCTIONS:\nDo NOT hallucinate links. You MUST map your recommendation to one of these exact, verified ET links ONLY:\n- https://economictimes.indiatimes.com/prime (For Premium deep analysis, macro)\n- https://economictimes.indiatimes.com/markets (For Live stock data, screener, signals)\n- https://economictimes.indiatimes.com/wealth (For Personal finance, mutual funds, taxes)\n- https://economictimes.indiatimes.com/tech (For Startup and technology news)\n- https://economictimes.indiatimes.com/mf (For strictly Mutual Funds)\n- https://economictimes.indiatimes.com/markets/options (For Options/Derivatives traders)\n\nYOU MUST RETURN JSON MATCHING THIS EXACT SCHEMA:\n{\n  \"assistantReply\": \"A welcome aboard message mentioning their dashboard is ready. Answer any final trailing thoughts they just had.\",\n  \"profile\": {\n    \"name\": \"Extract their name or use Operator\",\n    \"persona\": \"e.g. Emerging Alpha Seeker\",\n    \"summary\": \"2 sentence summary of their goals and risk profile.\",\n    \"riskTolerance\": \"low\" | \"medium\" | \"high\",\n    \"riskLabel\": \"Cautious\" | \"Balanced\" | \"Aggressive\",\n    \"experienceLevel\": \"e.g. Intermediate\",\n    \"interests\": [\"ET Markets\", \"AI\", \"Macro\"],\n    \"primaryGoal\": \"e.g. Wealth Creation\",\n    \"investmentHorizon\": \"e.g. 5+ years\",\n    \"financialIQ\": 75,\n    \"profileCompletion\": 100,\n    \"coreId\": \"OX-USER-1\",\n    \"insights\": [\n      { \"label\": \"Risk appetite\", \"value\": \"Balanced\", \"score\": 60 },\n      { \"label\": \"Experience\", \"value\": \"Intermediate\", \"score\": 70 },\n      { \"label\": \"Goal clarity\", \"value\": \"High\", \"score\": 85 }\n    ]\n  },\n  \"recommendations\": [\n    {\n      \"title\": \"ET Prime Daily Playbook\",\n      \"description\": \"Specific daily insights matched to their answers.\",\n      \"confidence\": 0.95,\n      \"reasoning\": \"You mentioned wanting macro analysis.\",\n      \"ctaLabel\": \"Open ET Prime\",\n      \"link\": \"https://economictimes.indiatimes.com/prime\",\n      \"source\": \"ET Prime\",\n      \"tags\": [\"Premium\", \"Macro\"]\n    }\n  ]\n}\nReturn EXACTLY 4 recommendations of array items.\n`;\n    try {\n      const gModel = genAI.getGenerativeModel({ model: 'gemini-2.5-flash', generationConfig: { responseMimeType: 'application/json' }});\n      const result = await gModel.generateContent(synthesisPrompt);\n      const data = JSON.parse(result.response.text());\n      \n      updatedSession.profile = { ...data.profile, lastActive: new Date().toISOString() };\n      updatedSession.recommendations = data.recommendations.map((r: any, i: number) => ({ ...r, id: `gemini-rec-${i}` }));\n      \n      if (isJustFinished) {\n        assistantReply = data.assistantReply || \"Your profile is fully calibrated! The ET Ecosystem dashboard is ready on your right.\";\n      }\n\n    } catch (err: any) {\n      console.error(\"Gemini Synthesis Error:\", err.message);\n    }\n  }\n\n  // Push the final AI response to the message array\n  updatedSession.messages.push({\n    id: crypto.randomUUID(),\n    role: 'assistant',\n    content: assistantReply,\n    timestamp: new Date().toISOString(),\n    status: 'complete',\n  });\n\n  return updatedSession;\n}"},{"path":"lib/server/session-store.ts","size":531,"sha256":"fe3d9942a6f1965600e9c042d493910571995bbc7c8cb06cbf8ae2035152204f","encoding":"utf8","content":"import { createFallbackPayload } from '../dummyData';\nimport { PersonalizationPayload } from '../../types';\n\nconst sessionStore = new Map<string, PersonalizationPayload>();\n\nexport function getOrCreateSession(sessionId?: string) {\n  const id = sessionId || crypto.randomUUID();\n  if (!sessionStore.has(id)) {\n    sessionStore.set(id, createFallbackPayload(id));\n  }\n  return sessionStore.get(id)!;\n}\n\nexport function saveSession(session: PersonalizationPayload) {\n  sessionStore.set(session.sessionId, session);\n  return session;\n}"},{"path":"lib/server/supabase.ts","size":347,"sha256":"e5363eb196bb2c83d52a6041b48156a4de235cfce809ae2d4fabfc043eb7a64d","encoding":"utf8","content":"import { createClient } from '@supabase/supabase-js';\n\nexport function getSupabaseServerClient() {\n  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;\n  const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;\n\n  if (!supabaseUrl || !supabaseAnonKey) {\n    return null;\n  }\n\n  return createClient(supabaseUrl, supabaseAnonKey);\n}"},{"path":"metadata.json","size":160,"sha256":"5f809ea697f996b00f6368d4f07b7b241af7211089f00c2b6a98c263f27aaa69","encoding":"utf8","content":"{\n  \"name\": \"Obsidian Flux — ET AI Concierge\",\n  \"description\": \"An AI-driven financial concierge system for ET products.\",\n  \"requestFramePermissions\": []\n}\n"},{"path":"next-env.d.ts","size":228,"sha256":"9dd9d642cdb87d4d5b3173217e0c45429b3e47a6f5cf5fb0ead6c644ec5fed01","encoding":"utf8","content":"/// <reference types=\"next\" />\n/// <reference types=\"next/image-types/global\" />\n\n// NOTE: This file should not be edited\n// see https://nextjs.org/docs/app/building-your-application/configuring/typescript for more information.\n"},{"path":"next.config.mjs","size":310,"sha256":"d873f8824ad85598b2c9f03e0d0d1a62f946440a8945341abf9aadf2f0a7ee69","encoding":"utf8","content":"/** @type {import('next').NextConfig} */\nconst nextConfig = {\n  reactStrictMode: true,\n  output: 'standalone',\n  images: {\n    remotePatterns: [\n      {\n        protocol: 'https',\n        hostname: 'picsum.photos',\n        port: '',\n        pathname: '/**',\n      },\n    ],\n  },\n};\n\nexport default nextConfig;\n"},{"path":"package-lock.json","size":235754,"sha256":"bf9a8e2104b14be9f4586b1191484304c5685eb142afbdb18180b28c80e940fe","encoding":"utf8","content":"{\n  \"name\": \"obsidian-flux-ai-concierge\",\n  \"version\": \"0.1.0\",\n  \"lockfileVersion\": 3,\n  \"requires\": true,\n  \"packages\": {\n    \"\": {\n      \"name\": \"obsidian-flux-ai-concierge\",\n      \"version\": \"0.1.0\",\n      \"dependencies\": {\n        \"@google/genai\": \"^1.29.0\",\n        \"clsx\": \"^2.1.1\",\n        \"lucide-react\": \"^0.546.0\",\n        \"motion\": \"^12.23.24\",\n        \"next\": \"14.2.23\",\n        \"react\": \"^18.3.1\",\n        \"react-dom\": \"^18.3.1\",\n        \"react-resizable-panels\": \"^4.7.5\",\n        \"tailwind-merge\": \"^2.5.2\"\n      },\n      \"devDependencies\": {\n        \"@tailwindcss/postcss\": \"^4.0.0\",\n        \"@types/node\": \"^22.14.0\",\n        \"@types/react\": \"^18.3.12\",\n        \"@types/react-dom\": \"^18.3.1\",\n        \"autoprefixer\": \"^10.4.21\",\n        \"eslint\": \"^8.57.1\",\n        \"eslint-config-next\": \"^14.2.23\",\n        \"postcss\": \"^8.4.47\",\n        \"tailwindcss\": \"^4.0.0\",\n        \"typescript\": \"~5.8.2\"\n      }\n    },\n 